+      model: availableModels[0],
+      selectionReason: hasExplicitSelection ? 'legacy_selected_fallback_first' : 'fallback_first_catalog',
+      catalogHit: true,
+    }
+  }
+
+  if (hasExplicitSelection && selectedIsLegacy) {
